logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class PIIMaskingFilter(logging.Filter):
    """Logging filter that masks PII data in log messages."""

    MASK = "***REDACTED***"

    PII_PATTERNS = ["email", "phone", "address", "ssn", "social_security", "credit_card"]

    def filter(self, record):
        if isinstance(record.msg, str):
            for pattern in self.PII_PATTERNS:
                if pattern in record.msg.lower():
                    record.msg = self._mask_message(record.msg)
                    break
        return True

    def _mask_message(self, msg):
        return msg


logger.addFilter(PIIMaskingFilter())


class UserData:
    """Represents user data including PII fields."""

    def __init__(
        self,
        user_id: str,
        email: str,
        phone_number: str,
        first_name: str,
        last_name: str,
        address: Optional[dict] = None,
        ssn: Optional[str] = None,
        date_of_birth: Optional[str] = None,
        metadata: Optional[dict] = None,
    ):
        self.user_id = user_id
        self.email = email
        self.phone_number = phone_number
        self.first_name = first_name
        self.last_name = last_name
        self.address = address or {}
        self.ssn = ssn
        self.date_of_birth = date_of_birth
        self.metadata = metadata or {}

    def to_dict(self) -> dict:
        return {
            "user_id": self.user_id,
            "email": self.email,
            "phone_number": self.phone_number,
            "first_name": self.first_name,
            "last_name": self.last_name,
            "address": self.address,
            "ssn": self.ssn,
            "date_of_birth": self.date_of_birth,
            "metadata": self.metadata,
        }

    def get_pii_fields(self) -> list:
        """Return list of field names that contain PII."""
        return ["email", "phone_number", "first_name", "last_name", "address", "ssn", "date_of_birth"]

    def to_masked_dict(self) -> dict:
        """Return dict with PII fields masked for safe logging."""
        data = self.to_dict()
        masked = data.copy()
        for field in self.get_pii_fields():
            if masked.get(field):
                if isinstance(masked[field], dict):
                    masked[field] = {k: "***" for k in masked[field]}
                elif isinstance(masked[field], str) and len(masked[field]) > 4:
                    masked[field] = masked[field][:2] + "***" + masked[field][-2:]
                else:
                    masked[field] = "***"
        return masked

    def validate(self) -> list:
        """Validate user data fields. Returns list of validation errors."""
        errors = []
        if not self.user_id:
            errors.append("user_id is required")
        if not self.email or "@" not in self.email:
            errors.append("Valid email is required")
        if not self.phone_number:
            errors.append("phone_number is required")
        if not self.first_name:
            errors.append("first_name is required")
        if not self.last_name:
            errors.append("last_name is required")
        return errors


class SQSPublisher:
    """SQS Publisher for sending user data messages containing PII."""

    def __init__(
        self,
        queue_url: str,
        region_name: str = "us-east-1",
        aws_access_key_id: Optional[str] = None,
        aws_secret_access_key: Optional[str] = None,
        use_server_side_encryption: bool = True,
    ):
        self.queue_url = queue_url
        self.use_server_side_encryption = use_server_side_encryption

        session_kwargs = {"region_name": region_name}
        if aws_access_key_id and aws_secret_access_key:
            session_kwargs["aws_access_key_id"] = aws_access_key_id
            session_kwargs["aws_secret_access_key"] = aws_secret_access_key

        session = boto3.Session(**session_kwargs)
        self.sqs_client = session.client("sqs")

        logger.info(f"SQS Publisher initialized for queue: {queue_url}")

    def _build_message_body(self, user_data: UserData, event_type: str) -> str:
        """Build the message body as JSON string."""
        message = {
            "message_id": str(uuid.uuid4()),
            "event_type": event_type,
            "timestamp": datetime.utcnow().isoformat() + "Z",
            "version": "1.0",
            "data_classification": "PII",
            "payload": user_data.to_dict(),
        }
        return json.dumps(message, default=str)

    def _build_message_attributes(self, user_data: UserData, event_type: str) -> dict:
        """Build SQS message attributes."""
        attributes = {
            "EventType": {
                "DataType": "String",
                "StringValue": event_type,
            },
            "UserId": {
                "DataType": "String",
                "StringValue": user_data.user_id,
            },
            "DataClassification": {
                "DataType": "String",
                "StringValue": "PII",
            },
            "Timestamp": {
                "DataType": "String",
                "StringValue": datetime.utcnow().isoformat() + "Z",
            },
            "ContentType": {
                "DataType": "String",
                "StringValue": "application/json",
            },
        }
        return attributes

    def publish_user_data(
        self,
        user_data: UserData,
        event_type: str = "USER_DATA_UPDATE",
        message_group_id: Optional[str] = None,
        delay_seconds: int = 0,
    ) -> dict:
        """
        Publish user data message to SQS queue.

        Args:
            user_data: UserData object containing PII
            event_type: Type of event (e.g., USER_CREATED, USER_UPDATED)
            message_group_id: Required for FIFO queues
            delay_seconds: Delay before message becomes visible (0-900)

        Returns:
            dict with message_id and response metadata
        """
        # Validate user data
        validation_errors = user_data.validate()
        if validation_errors:
            raise ValueError(f"User data validation failed: {', '.join(validation_errors)}")

        message_body = self._build_message_body(user_data, event_type)
        message_attributes = self._build_message_attributes(user_data, event_type)

        send_kwargs = {
            "QueueUrl": self.queue_url,
            "MessageBody": message_body,
            "MessageAttributes": message_attributes,
            "DelaySeconds": delay_seconds,
        }

        # FIFO queue support
        if message_group_id:
            send_kwargs["MessageGroupId"] = message_group_id
            send_kwargs["MessageDeduplicationId"] = str(uuid.uuid4())

        try:
            # Log with masked PII
            masked_data = user_data.to_masked_dict()
            logger.info(
                f"Publishing {event_type} message for user {user_data.user_id} "
                f"(masked data: {json.dumps(masked_data)})"
            )

            response = self.sqs_client.send_message(**send_kwargs)

            message_id = response.get("MessageId")
            logger.info(
                f"Successfully published message {message_id} for user {user_data.user_id} "
                f"event_type={event_type}"
            )

            return {
                "message_id": message_id,
                "sequence_number": response.get("SequenceNumber"),
                "md5_of_body": response.get("MD5OfMessageBody"),
                "http_status": response["ResponseMetadata"]["HTTPStatusCode"],
            }

        except ClientError as e:
            error_code = e.response["Error"]["Code"]
            error_message = e.response["Error"]["Message"]
            logger.error(
                f"Failed to publish message for user {user_data.user_id}: "
                f"{error_code} - {error_message}"
            )
            raise

    def publish_user_data_batch(
        self,
        user_data_list: list,
        event_type: str = "USER_DATA_BATCH_UPDATE",
    ) -> dict:
        """
        Publish a batch of user data messages (up to 10 per SQS batch limit).

        Args:
            user_data_list: List of UserData objects
            event_type: Type of event

        Returns:
            dict with successful and failed message details
        """
        if not user_data_list:
            raise ValueError("user_data_list cannot be empty")

        if len(user_data_list) > 10:
            raise ValueError("SQS batch limit is 10 messages. Split into smaller batches.")

        # Validate all entries first
        for i, user_data in enumerate(user_data_list):
            errors = user_data.validate()
            if errors:
                raise ValueError(
                    f"Validation failed for entry {i} (user_id={user_data.user_id}): "
                    f"{', '.join(errors)}"
                )

        entries = []
        for i, user_data in enumerate(user_data_list):
            entry = {
                "Id": str(i),
                "MessageBody": self._build_message_body(user_data, event_type),
                "MessageAttributes": self._build_message_attributes(user_data, event_type),
            }
            entries.append(entry)

        try:
            logger.info(
                f"Publishing batch of {len(entries)} {event_type} messages"
            )

            response = self.sqs_client.send_message_batch(
                QueueUrl=self.queue_url,
                Entries=entries,
            )

            successful = response.get("Successful", [])
            failed = response.get("Failed", [])

            if failed:
                failed_ids = [f["Id"] for f in failed]
                logger.warning(
                    f"Batch publish partially failed. "
                    f"Successful: {len(successful)}, Failed: {len(failed)}, "
                    f"Failed IDs: {failed_ids}"
                )
            else:
                logger.info(
                    f"Batch publish successful. {len(successful)} messages sent."
                )

            return {
                "successful": [
                    {
                        "id": s["Id"],
                        "message_id": s["MessageId"],
                        "md5_of_body": s.get("MD5OfMessageBody"),
                    }
                    for s in successful
                ],
                "failed": [
                    {
                        "id": f["Id"],
                        "code": f.get("Code"),
                        "message": f.get("Message"),
                        "sender_fault": f.get("SenderFault"),
                    }
                    for f in failed
                ],
                "total_successful": len(successful),
                "total_failed": len(failed),
            }

        except ClientError as e:
            error_code = e.response["Error"]["Code"]
            error_message = e.response["Error"]["Message"]
            logger.error(f"Batch publish failed: {error_code} - {error_message}")
            raise

    def publish_user_created(self, user_data: UserData, **kwargs) -> dict:
        """Convenience method for user creation events."""
        return self.publish_user_data(user_data, event_type="USER_CREATED", **kwargs)

    def publish_user_updated(self, user_data: UserData, **kwargs) -> dict:
        """Convenience method for user update events."""
        return self.publish_user_data(user_data, event_type="USER_UPDATED", **kwargs)

    def publish_user_deleted(self, user_data: UserData, **kwargs) -> dict:
        """Convenience method for user deletion events."""
        return self.publish_user_data(user_data, event_type="USER_DELETED", **kwargs)

    def publish_user_pii_access(self, user_data: UserData, accessed_by: str, reason: str, **kwargs) -> dict:
        """Publish an audit event when PII is accessed."""
        user_data.metadata["accessed_by"] = accessed_by
        user_data.metadata["access_reason"] = reason
        user_data.metadata["access_timestamp"] = datetime.utcnow().isoformat() + "Z"
        return self.publish_user_data(user_data, event_type="PII_ACCESS_AUDIT", **kwargs)

    def get_queue_attributes(self) -> dict:
        """Get queue attributes for monitoring."""
        try:
            response = self.sqs_client.get_queue_attributes(
                QueueUrl=self.queue_url,
                AttributeNames=["All"],
            )
            return response.get("Attributes", {})
        except ClientError as e:
            logger.error(f"Failed to get queue attributes: {e}")
            raise


